Creating new sprites without recycling - causes GC spikes. How can this be refactored?

output:
Object pooling reuses sprite instances instead of creating and destroying them. This prevents garbage collection spikes that cause frame drops, especially on mobile devices with frequent enemy spawning.

```js
var EnemyPool = { _pool: [], get: function(p) {
    if (this._pool.length > 0) { var e = this._pool.pop(); e.setVisible(true); e.stopAllActions(); return e; }
    var e = new cc.Sprite('res/enemy.png'); p.addChild(e); return e;
}, recycle: function(e) { e.setVisible(false); e.stopAllActions(); this._pool.push(e); } };

this.schedule(function() {
    var e = EnemyPool.get(this);
    e.setPosition(500, Math.random() * 320);
    e.runAction(cc.sequence(
        cc.moveTo(4, cc.p(-50, e.y)),
        cc.callFunc(function() { EnemyPool.recycle(e); })
    ));
}.bind(this), 2.0);
```

